import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"潭柘寺","description":"","frontmatter":{},"headers":[],"relativePath":"religion/tanzhe.md","filePath":"religion/tanzhe.md","lastUpdated":1784712887000}'),o={name:"religion/tanzhe.md"};function n(i,t,d,h,s,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="潭柘寺" tabindex="-1">潭柘寺 <a class="header-anchor" href="#潭柘寺" aria-label="Permalink to &quot;潭柘寺&quot;">​</a></h1><blockquote><p>&quot;先有潭柘寺，后有北京城。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>潭柘寺位于北京市门头沟区，是北京最古老的佛教寺院之一，也是北京历史最悠久的名刹。潭柘寺始建于西晋愍帝建兴四年（316年），距今已有1700余年历史，比北京城建城还早800年，故有&quot;先有潭柘寺，后有北京城&quot;之说。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:00-16:30</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">50元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，秋季银杏最美</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线苹果园站转公交931路</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市门头沟区潭柘寺镇</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>潭柘寺始建于西晋建兴四年（316年），原名嘉福寺，是北京最早的佛教寺院。</p><h3 id="发展" tabindex="-1">发展 <a class="header-anchor" href="#发展" aria-label="Permalink to &quot;发展&quot;">​</a></h3><ul><li><strong>唐代</strong>：华严宗高僧在此讲经</li><li><strong>金代</strong>：金熙宗曾到此进香</li><li><strong>元代</strong>：元世祖忽必烈的女儿妙严公主在此出家</li><li><strong>明代</strong>：明成祖朱棣曾到此进香</li><li><strong>清代</strong>：康熙、乾隆多次到此进香，潭柘寺达到鼎盛</li></ul><h3 id="近代" tabindex="-1">近代 <a class="header-anchor" href="#近代" aria-label="Permalink to &quot;近代&quot;">​</a></h3><p>民国时期，潭柘寺逐渐衰落。新中国成立后，潭柘寺得到保护，1980年代修复后对外开放。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><p>潭柘寺依山而建，坐北朝南，建筑层层递升。</p><h3 id="山门" tabindex="-1">山门 <a class="header-anchor" href="#山门" aria-label="Permalink to &quot;山门&quot;">​</a></h3><p>山门是潭柘寺的入口，门前有石桥。</p><h3 id="天王殿" tabindex="-1">天王殿 <a class="header-anchor" href="#天王殿" aria-label="Permalink to &quot;天王殿&quot;">​</a></h3><p>天王殿是潭柘寺的第一重大殿，供奉弥勒佛和四大天王。</p><h3 id="大雄宝殿" tabindex="-1">大雄宝殿 <a class="header-anchor" href="#大雄宝殿" aria-label="Permalink to &quot;大雄宝殿&quot;">​</a></h3><p>大雄宝殿是潭柘寺的主殿，供奉释迦牟尼佛。</p><h4 id="琉璃鸱吻" tabindex="-1">琉璃鸱吻 <a class="header-anchor" href="#琉璃鸱吻" aria-label="Permalink to &quot;琉璃鸱吻&quot;">​</a></h4><p>大雄宝殿顶上有琉璃鸱吻，是潭柘寺的标志性建筑。</p><h3 id="帝王树" tabindex="-1">帝王树 <a class="header-anchor" href="#帝王树" aria-label="Permalink to &quot;帝王树&quot;">​</a></h3><p>潭柘寺内有一棵古银杏树，高30余米，胸径约4米，植于辽代，距今已有千年历史，称为&quot;帝王树&quot;。</p><h4 id="帝王树传说" tabindex="-1">帝王树传说 <a class="header-anchor" href="#帝王树传说" aria-label="Permalink to &quot;帝王树传说&quot;">​</a></h4><p>相传每换一个皇帝，帝王树就会长出一个新枝，因此得名&quot;帝王树&quot;。</p><h3 id="配王树" tabindex="-1">配王树 <a class="header-anchor" href="#配王树" aria-label="Permalink to &quot;配王树&quot;">​</a></h3><p>帝王树旁还有一棵&quot;配王树&quot;，也是千年银杏。</p><h3 id="流杯亭" tabindex="-1">流杯亭 <a class="header-anchor" href="#流杯亭" aria-label="Permalink to &quot;流杯亭&quot;">​</a></h3><p>流杯亭是潭柘寺的特色建筑，亭内有水槽，可以将酒杯放在水中漂流。</p><h3 id="楞严坛" tabindex="-1">楞严坛 <a class="header-anchor" href="#楞严坛" aria-label="Permalink to &quot;楞严坛&quot;">​</a></h3><p>楞严坛是潭柘寺的戒坛，是僧人受戒的地方。</p><h3 id="塔林" tabindex="-1">塔林 <a class="header-anchor" href="#塔林" aria-label="Permalink to &quot;塔林&quot;">​</a></h3><p>潭柘寺后有塔林，埋葬着历代高僧。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约3-4小时）</strong>：</p><p>山门 → 天王殿 → 大雄宝殿 → 帝王树 → 配王树 → 流杯亭 → 楞严坛 → 塔林 → 出寺</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;">公交</td><td style="text-align:left;">地铁1号线苹果园站 → 931路 → 潭柘寺</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">莲石路 → 108国道 → 潭柘寺</td></tr><tr><td style="text-align:left;">旅游专线</td><td style="text-align:left;">前门有旅游专线</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票较贵</strong>：门票50元</li><li><strong>帝王树必看</strong>：千年银杏是精华</li><li><strong>秋季最美</strong>：秋季银杏金黄，最美</li><li><strong>斋饭</strong>：寺内有斋饭供应</li><li><strong>爬山</strong>：寺庙依山而建，需要爬山</li><li><strong>结合游览</strong>：可与戒台寺一起游览（相距约10公里）</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">戒台寺</td><td style="text-align:center;">约10公里</td><td style="text-align:left;">中国三大戒台之一</td></tr><tr><td style="text-align:left;">定都峰</td><td style="text-align:center;">约5公里</td><td style="text-align:left;">俯瞰北京城</td></tr><tr><td style="text-align:left;">妙峰山</td><td style="text-align:center;">约20公里</td><td style="text-align:left;">道教名山</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>潭柘寺是北京最古老的佛教寺院，有&quot;先有潭柘寺，后有北京城&quot;之说。</p><p>潭柘寺保存了大量珍贵文物，是研究北京佛教史的重要场所。</p><p>潭柘寺的&quot;帝王树&quot;是千年银杏，是北京最古老的树木之一。</p><hr><p><strong>📍 地址</strong>：北京市门头沟区潭柘寺镇 <strong>📞 电话</strong>：010-60862500</p>',51)])])}const b=a(o,[["render",n]]);export{c as __pageData,b as default};
